sourcesContent:
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Header from './Header';
import { rfidService } from '../services/rfidService';
import { DragDropContext, Droppable, Draggable } from 'react-beautiful-dnd';

const API_ENDPOINTS = [
  {
    id: 'save-transaction',
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDTransactionDetails',
    method: 'POST',
    description: 'Save new RFID transaction details with complete product information including weights, pricing, and status.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-save text-white',
    highlight: 'primary',
    gradient: 'linear-gradient(135deg, #8E2DE2, #4A00E0)',
    sampleBody: {
      client_code: "LS000123",
      branch_id: "string",
      counter_id: "string",
      RFIDNumber: "CZ3506",
      Itemcode: "SAU124",
      category_id: "Gold",
      product_id: "Tops",
      design_id: "Fancy Top",
      purity_id: "22CT",
      grosswt: "20.800",
      stonewt: "0.500",
      diamondheight: "0.250",
      netwt: "19.250",
      box_details: "Box A",
      size: 0,
      stoneamount: "20",
      diamondAmount: "20",
      HallmarkAmount: "35",
      MakingPerGram: "10",
      MakingPercentage: "5",
      MakingFixedAmt: "37",
      MRP: "5000",
      imageurl: "",
      status: "ApiActive"
    }
  },
  {
    id: 'update-transaction',
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDTransactionDetails',
    method: 'POST',
    description: 'Update the status of RFID items (e.g., mark as Sold).',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-edit text-white',
    highlight: 'info',
    gradient: 'linear-gradient(135deg, #4A00E0, #8E2DE2)',
    sampleBody: {
      client_code: "LS000186",
      RFIDNumber: "CZ3581",
      status: "Sold"
    }
  },
  {
    id: 'get-transaction',
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDTransactionDetails',
    method: 'POST',
    description: 'Retrieve all active RFID transactions for a client.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-search text-white',
    highlight: 'primary',
    gradient: 'linear-gradient(135deg, #06beb6, #48b1bf)',
    sampleBody: {
      client_code: "LS000186",
      status: "ApiActive"
    }
  },
  {
    id: 'get-all-device',
    name: 'Get All RFID Device Details',
    endpoint: 'GetAllRFIDDetails',
    method: 'POST',
    description: 'Retrieve all RFID device details for the specified device.',
    baseUrl: 'https://rrgold.loyalstring.co.in/api/RFIDDevice',
    authRequired: true,
    icon: 'fas fa-mobile-alt text-white',
    highlight: 'info',
    gradient: 'linear-gradient(135deg, #2193b0, #6dd5ed)',
    sampleBody: {
      ClientCode: "LS000186",
      DeviceId: "Sai"
    }
  },
  {
    id: 'delete-specific',
    name: 'Delete Specific Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    description: 'Remove specific items from labelled stock inventory.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-trash-alt text-white',
    highlight: 'danger',
    gradient: 'linear-gradient(135deg, #d60000, #ff0000)',
    sampleBody: {
      ClientCode: "LS000186",
      ItemCodes: ["ITEM001", "ITEM002"]
    }
  },
  {
    id: 'delete-all',
    name: 'Delete All Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    description: 'Remove all items from labelled stock inventory for a client.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-trash text-white',
    highlight: 'danger',
    gradient: 'linear-gradient(135deg, #FF416C, #FF4B2B)',
    sampleBody: {
      ClientCode: "LS000186",
      ItemCodes: []
    }
  },
  {
    id: 'delete-by-client-device',
    name: 'Delete RFID By Client And Device',
    endpoint: 'DeleteRFIDByClientAndDevice',
    method: 'POST',
    description: 'Delete RFID data for a specific client and device combination.',
    baseUrl: 'https://rrgold.loyalstring.co.in/api/RFIDDevice',
    authRequired: true,
    icon: 'fas fa-trash-alt text-white',
    highlight: 'warning',
    gradient: 'linear-gradient(135deg, #f7b733, #fc4a1a)',
    sampleBody: {
      ClientCode: "LS000186",
      DeviceId: "Sai"
    }
  }
];

const Dashboard = () => {
  const navigate = useNavigate();
  const [userInfo, setUserInfo] = useState({});
  const [selectedEndpoint, setSelectedEndpoint] = useState(null);
  const [response, setResponse] = useState(null);
  const [loading, setLoading] = useState(false);
  const [requestBody, setRequestBody] = useState({});
  const [responseBody, setResponseBody] = useState({});
  const [clientError, setClientError] = useState('');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [endpointsOrder, setEndpointsOrder] = useState(API_ENDPOINTS.map(e => e.id));

  useEffect(() => {
    const userInfo = JSON.parse(localStorage.getItem('userInfo')) || {};
    setUserInfo(userInfo);
  }, []);

  const getOrderedEndpoints = () => endpointsOrder.map(id => API_ENDPOINTS.find(e => e.id === id));

  const onDragEnd = (result) => {
    if (!result.destination) return;
    const newOrder = Array.from(endpointsOrder);
    const [removed] = newOrder.splice(result.source.index, 1);
    newOrder.splice(result.destination.index, 0, removed);
    setEndpointsOrder(newOrder);
  };

  const handleEndpointClick = (endpoint) => {
    setSelectedEndpoint(endpoint);
    setResponse(null);
    setResponseBody({});
    const newRequestBody = { ...endpoint.sampleBody };
    if (newRequestBody.client_code) {
      newRequestBody.client_code = userInfo.ClientCode;
    }
    if (newRequestBody.ClientCode) {
      newRequestBody.ClientCode = userInfo.ClientCode;
    }
    setRequestBody(newRequestBody);
    setClientError('');
    setSidebarOpen(false);
  };

  const validateClientCode = (body) => {
    const clientCode = body.client_code || body.ClientCode;
    if (clientCode !== userInfo.ClientCode) {
      setClientError('You can only make requests with your own client code');
      return false;
    }
    setClientError('');
    return true;
  };

  const handleFieldChange = (field, value) => {
    setRequestBody(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleResponseBodyChange = (value) => {
    try {
      const parsedBody = JSON.parse(value);
      setResponseBody(parsedBody);
    } catch (error) {
      console.error('Invalid JSON:', error);
    }
  };

  const handleTestEndpoint = async () => {
    if (!selectedEndpoint) return;
    if (!validateClientCode(requestBody)) return;

    setLoading(true);
    try {
      let result;
      const clientCode = userInfo.ClientCode;
      const token = localStorage.getItem('token');

      if (!token && (selectedEndpoint.endpoint === 'SaveRFIDTransactionDetails' || 
          selectedEndpoint.endpoint === 'UpdateRFIDTransactionDetails')) {
        toast.error('Authentication required. Please login again.');
        navigate('/login');
        return;
      }

      switch (selectedEndpoint.endpoint) {
        case 'SaveRFIDTransactionDetails':
          result = await fetch('https://soni.loyalstring.co.in/api/ProductMaster/SaveRFIDTransactionDetails', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify([requestBody])
          });
          if (result.status === 401) {
            toast.error('Session expired. Please login again.');
            navigate('/login');
            return;
          }
          result = await result.json();
          break;

        case 'UpdateRFIDTransactionDetails':
          result = await fetch('https://soni.loyalstring.co.in/api/ProductMaster/UpdateRFIDTransactionDetails', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${token}`
            },
            body: JSON.stringify([requestBody])
          });
          if (result.status === 401) {
            toast.error('Session expired. Please login again.');
            navigate('/login');
            return;
          }
          result = await result.json();
          break;

        case 'GetRFIDTransactionDetails':
          result = await rfidService.getRFIDTransactions(clientCode);
          break;

        case 'DeleteLabelledStockItems':
          result = await rfidService.deleteLabelledStock(clientCode, requestBody.ItemCodes);
          break;

        case 'GetAllRFIDDetails':
          result = await fetch('https://rrgold.loyalstring.co.in/api/RFIDDevice/GetAllRFIDDetails', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify(requestBody)
          });
          result = await result.json();
          break;

        case 'DeleteRFIDByClientAndDevice':
          result = await fetch('https://rrgold.loyalstring.co.in/api/RFIDDevice/DeleteRFIDByClientAndDevice', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify(requestBody)
          });
          result = await result.json();
          break;

        default:
          break;
      }

      setResponse(result);
      setResponseBody(result);
      toast.success('API call successful!');
    } catch (error) {
      console.error('API Error:', error);
      setResponse(error.response?.data || error.message);
      setResponseBody(error.response?.data || { error: error.message });
      toast.error('API call failed. Please check console for details.');
    } finally {
      setLoading(false);
    }
  };

  const renderRequestBodyFields = () => {
    if (!selectedEndpoint) return null;

    // For Delete All Stock Items, only show ClientCode
    if (selectedEndpoint.name === 'Delete All Stock Items') {
      return (
        <div className="row g-3">
          <div className="col-12">
            <label className="form-label fw-medium">ClientCode</label>
            <input
              type="text"
              className="form-control"
              value={requestBody.ClientCode}
              disabled
              style={{ 
                borderRadius: '8px', 
                fontSize: '0.9rem',
                backgroundColor: '#f8f9fa' 
              }}
            />
          </div>
        </div>
      );
    }

    const fields = Object.entries(requestBody);
    return (
      <div className="row g-3">
        {fields.map(([key, value]) => {
          // Special handling for ItemCodes array
          if (key === 'ItemCodes' && Array.isArray(value)) {
            return (
              <div className="col-12" key={key}>
                <label className="form-label fw-medium">{key}</label>
                <input
                  type="text"
                  className="form-control"
                  value={value.join(', ')}
                  onChange={(e) => handleFieldChange(key, e.target.value.split(',').map(item => item.trim()))}
                  placeholder="Enter item codes separated by commas"
                  style={{ borderRadius: '8px', fontSize: '0.9rem' }}
                />
              </div>
            );
          }

          // Client code field (disabled)
          if (key === 'client_code' || key === 'ClientCode') {
            return (
              <div className="col-md-6" key={key}>
                <label className="form-label fw-medium">{key}</label>
                <input
                  type="text"
                  className="form-control"
                  value={value}
                  disabled
                  style={{ 
                    borderRadius: '8px', 
                    fontSize: '0.9rem',
                    backgroundColor: '#f8f9fa' 
                  }}
                />
              </div>
            );
          }

          // Regular fields
          return (
            <div className="col-md-6" key={key}>
              <label className="form-label fw-medium">{key}</label>
              <input
                type={typeof value === 'number' ? 'number' : 'text'}
                className="form-control"
                value={value}
                onChange={(e) => handleFieldChange(key, e.target.value)}
                style={{ borderRadius: '8px', fontSize: '0.9rem' }}
              />
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #fff 0%, #f8f9fa 60%, #ececec 100%)',
      fontFamily: 'Poppins, Inter, sans-serif',
      transition: 'all 0.4s cubic-bezier(.68,-0.55,.27,1.55)'
    }}>
      <Header userInfo={userInfo} />
      <div className="container py-4 flex-grow-1" style={{ maxWidth: '1400px', display: 'flex', gap: 32 }}>
        {/* Sidebar */}
        <div style={{
          width: sidebarOpen ? 370 : 0,
          minWidth: sidebarOpen ? 320 : 0,
          maxWidth: 400,
          transition: 'width 0.5s cubic-bezier(.68,-0.55,.27,1.55), min-width 0.5s cubic-bezier(.68,-0.55,.27,1.55)',
          overflow: 'hidden',
          zIndex: 10
        }}>
          <div className="card shadow-lg border-0" style={{
            borderRadius: '15px',
            background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
            minWidth: 320,
            fontFamily: 'Poppins, Inter, sans-serif',
            boxShadow: sidebarOpen ? '0 8px 32px #0078d422' : 'none',
            opacity: sidebarOpen ? 1 : 0,
            pointerEvents: sidebarOpen ? 'auto' : 'none',
            transition: 'opacity 0.4s cubic-bezier(.68,-0.55,.27,1.55)'
          }}>
            <div className="card-body p-4">
              <h5 className="mb-4 fw-bold text-primary" style={{ fontFamily: 'Poppins, Inter, sans-serif' }}>API Endpoints</h5>
              <DragDropContext onDragEnd={onDragEnd}>
                <Droppable droppableId="api-endpoints">
                  {(provided) => (
                    <div className="list-group" ref={provided.innerRef} {...provided.droppableProps}>
                      {getOrderedEndpoints().map((endpoint, idx) => (
                        <Draggable key={endpoint.id} draggableId={endpoint.id} index={idx}>
                          {(provided, snapshot) => (
                            <button
                              ref={provided.innerRef}
                              {...provided.draggableProps}
                              {...provided.dragHandleProps}
                              className={`list-group-item list-group-item-action border-0 mb-3 ${selectedEndpoint?.id === endpoint.id ? 'active' : ''}`}
                              onClick={() => handleEndpointClick(endpoint)}
                              style={{
                                borderRadius: '10px',
                                background: selectedEndpoint?.id === endpoint.id ? endpoint.gradient : 'white',
                                transition: 'all 0.3s',
                                transform: snapshot.isDragging ? 'scale(1.04)' : (selectedEndpoint?.id === endpoint.id ? 'scale(1.02)' : 'scale(1)'),
                                boxShadow: snapshot.isDragging ? '0 12px 32px #0078d422' : (selectedEndpoint?.id === endpoint.id ? '0 8px 16px rgba(0,0,0,0.1)' : '0 4px 6px rgba(0,0,0,0.05)'),
                                fontSize: '0.9rem',
                                fontFamily: 'Poppins, Inter, sans-serif',
                                ...provided.draggableProps.style
                              }}
                            >
                              <div className="d-flex align-items-center">
                                <div className="me-3" style={{
                                  width: '32px',
                                  height: '32px',
                                  borderRadius: '8px',
                                  background: endpoint.gradient,
                                  display: 'flex',
                                  alignItems: 'center',
                                  justifyContent: 'center',
                                  fontFamily: 'Poppins, Inter, sans-serif'
                                }}>
                                  <i className={endpoint.icon}></i>
                                </div>
                                <div>
                                  <h6 className={`mb-1 ${selectedEndpoint?.id === endpoint.id ? 'text-white' : 'text-dark'}`} style={{ fontSize: '0.9rem', fontFamily: 'Poppins, Inter, sans-serif' }}>
                                    {endpoint.name}
                                  </h6>
                                  <small className={selectedEndpoint?.id === endpoint.id ? 'text-white-50' : 'text-muted'} style={{ fontSize: '0.8rem', fontFamily: 'Poppins, Inter, sans-serif' }}>
                                    {endpoint.method} {endpoint.endpoint}
                                  </small>
                                </div>
                              </div>
                            </button>
                          )}
                        </Draggable>
                      ))}
                      {provided.placeholder}
                    </div>
                  )}
                </Droppable>
              </DragDropContext>
            </div>
          </div>
        </div>
        {/* Main Panel */}
        <div style={{
          flex: 1,
          minWidth: 0,
          transition: 'all 0.5s cubic-bezier(.68,-0.55,.27,1.55)',
          marginLeft: sidebarOpen ? 0 : -60,
          maxWidth: sidebarOpen ? 'calc(100% - 370px)' : '100%',
          width: '100%',
          fontFamily: 'Poppins, Inter, sans-serif',
          boxShadow: !sidebarOpen ? '0 8px 32px #0078d422' : 'none',
          borderRadius: 24
        }}>
          <div className="card shadow-lg border-0" style={{
            borderRadius: '15px',
            background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
            minHeight: 600,
            fontFamily: 'Poppins, Inter, sans-serif',
            transition: 'all 0.5s cubic-bezier(.68,-0.55,.27,1.55)'
          }}>
            <div className="card-body p-4">
              {/* Sidebar toggle button */}
              {!sidebarOpen && (
                <button
                  onClick={() => setSidebarOpen(true)}
                  style={{
                    position: 'absolute',
                    left: 24,
                    top: 24,
                    zIndex: 20,
                    background: 'linear-gradient(90deg, #0078d4 0%, #5470FF 100%)',
                    color: '#fff',
                    border: 'none',
                    borderRadius: 12,
                    padding: '10px 22px',
                    fontWeight: 700,
                    fontSize: 18,
                    cursor: 'pointer',
                    boxShadow: '0 2px 12px #0078d422',
                    fontFamily: 'Poppins, Inter, sans-serif',
                    transition: 'background 0.2s, transform 0.2s',
                    letterSpacing: 0.1
                  }}
                  onMouseOver={e => {
                    e.currentTarget.style.background = 'linear-gradient(90deg, #5470FF 0%, #0078d4 100%)';
                    e.currentTarget.style.transform = 'scale(1.04)';
                  }}
                  onMouseOut={e => {
                    e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #5470FF 100%)';
                    e.currentTarget.style.transform = 'scale(1)';
                  }}
                >
                  <i className="fas fa-bars me-2"></i> Show Endpoints
                </button>
              )}
              {selectedEndpoint ? (
                <div className="card shadow-lg border-0" style={{ 
                  borderRadius: '15px', 
                  background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)'
                }}>
                  <div className="card-body p-4">
                    <div className="d-flex align-items-center mb-4">
                      <h5 className="fw-bold mb-0" style={{ color: '#333' }}>
                        {selectedEndpoint.name}
                      </h5>
                      <span className="badge bg-primary ms-2" style={{ fontSize: '0.8rem' }}>{selectedEndpoint.method}</span>
                    </div>

                    <div className="mb-4">
                      <h6 className="fw-bold mb-2" style={{ fontSize: '0.9rem' }}>Description</h6>
                      <p className="text-muted mb-0" style={{ fontSize: '0.9rem' }}>{selectedEndpoint.description}</p>
                    </div>

                    <div className="mb-4">
                      <h6 className="fw-bold mb-3" style={{ fontSize: '0.9rem' }}>Request Body</h6>
                      <div className="position-relative" style={{ 
                        maxHeight: '400px', 
                        overflowY: 'auto',
                        padding: '15px',
                        backgroundColor: '#f8f9fa',
                        borderRadius: '10px',
                        border: '1px solid #dee2e6'
                      }}>
                        {renderRequestBodyFields()}
                        {clientError && (
                          <div className="alert alert-danger mt-3" style={{ fontSize: '0.85rem' }}>
                            {clientError}
                          </div>
                        )}
                        <div className="alert alert-info mt-3" style={{ fontSize: '0.85rem' }}>
                          <i className="fas fa-info-circle me-2"></i>
                          Client code is locked to your account for security
                        </div>
                      </div>
                    </div>

                    <button
                      className="btn btn-primary px-4 py-2"
                      onClick={handleTestEndpoint}
                      disabled={loading}
                      style={{
                        background: selectedEndpoint.gradient,
                        border: 'none',
                        borderRadius: '10px',
                        transition: 'all 0.3s ease',
                        fontSize: '0.9rem'
                      }}
                    >
                      {loading ? (
                        <>
                          <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                          Sending...
                        </>
                      ) : (
                        <>
                          <i className="fas fa-paper-plane me-2"></i>
                          Send Request
                        </>
                      )}
                    </button>

                    {response && (
                      <div className="mt-4">
                        <h6 className="fw-bold mb-3" style={{ fontSize: '0.9rem' }}>Response</h6>
                        <div className="response-container">
                          <textarea
                            className="form-control"
                            style={{
                              height: '200px',
                              fontFamily: 'monospace',
                              fontSize: '0.85rem',
                              backgroundColor: '#f8f9fa',
                              border: '1px solid #dee2e6',
                              borderRadius: '10px'
                            }}
                            value={JSON.stringify(responseBody, null, 2)}
                            onChange={(e) => handleResponseBodyChange(e.target.value)}
                          />
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              ) : (
                <div className="card shadow-lg border-0" style={{ 
                  borderRadius: '15px', 
                  background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
                  height: '100%'
                }}>
                  <div className="card-body p-4">
                    <div className="text-center mb-4">
                      <div style={{
                        width: '80px',
                        height: '80px',
                        margin: '0 auto',
                        background: 'linear-gradient(135deg, #0078d4 0%, #5470FF 100%)',
                        borderRadius: '50%',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        marginBottom: '20px'
                      }}>
                        <i className="fas fa-shield-alt text-white" style={{ fontSize: '2rem' }}></i>
                      </div>
                      <h4 className="fw-bold mb-3">Secure RFID Integration</h4>
                      <p className="text-muted mb-4">Select an endpoint from the left to start making secure API requests for your RFID operations.</p>
                    </div>

                    <div className="row g-4">
                      <div className="col-md-6">
                        <div className="p-3 h-100" style={{ 
                          background: '#f8f9fa', 
                          borderRadius: '10px',
                          transition: 'all 0.3s ease',
                          cursor: 'pointer',
                          border: '1px solid transparent',
                          height: '100%'
                        }} onMouseEnter={e => {
                          e.currentTarget.style.transform = 'translateY(-5px)';
                          e.currentTarget.style.boxShadow = '0 10px 20px rgba(0,0,0,0.1)';
                          e.currentTarget.style.borderColor = '#4A00E0';
                        }} onMouseLeave={e => {
                          e.currentTarget.style.transform = 'translateY(0)';
                          e.currentTarget.style.boxShadow = 'none';
                          e.currentTarget.style.borderColor = 'transparent';
                        }}>
                          <div className="d-flex align-items-center mb-2">
                            <i className="fas fa-save text-primary me-2"></i>
                            <h6 className="mb-0">Save Transactions</h6>
                          </div>
                          <p className="text-muted small mb-0">Securely save new RFID transaction details with complete product information.</p>
                        </div>
                      </div>
                      <div className="col-md-6">
                        <div className="p-3 h-100" style={{ 
                          background: '#f8f9fa', 
                          borderRadius: '10px',
                          transition: 'all 0.3s ease',
                          cursor: 'pointer',
                          border: '1px solid transparent',
                          height: '100%'
                        }} onMouseEnter={e => {
                          e.currentTarget.style.transform = 'translateY(-5px)';
                          e.currentTarget.style.boxShadow = '0 10px 20px rgba(0,0,0,0.1)';
